import vex
from smolagents import Agent

agent = Agent(tools=[firewall_tool])

@vex.verify(policies=["human_approval_required"], threshold="critical")
def approved_response(prompt):
    result = agent.run(prompt)
    if "block_ip" in result.tool_calls:
        approval = vex.request_human_approval(result)
        if not approval:
            raise ValueError("Action blocked")
    return result

